from typing import List

def longestIncreasingSubsequence(data: str) -> int:
    nums = list(map(int, data.split()))

    def is_increasing(subseq):
        return all(subseq[i] < subseq[i + 1] for i in range(len(subseq) - 1))

    def generate_subsequences(index, current):
        if index == len(nums):
            if is_increasing(current):
                subsequences.append(current)
            return
        generate_subsequences(index + 1, current)
        generate_subsequences(index + 1, current + [nums[index]])

    subsequences = []
    generate_subsequences(0, [])
    return max((len(subseq) for subseq in subsequences), default=0)

