function longestIncreasingSubsequence(data) {
    const nums = data.split(' ').map(Number);

    function isIncreasing(subseq) {
        for (let i = 1; i < subseq.length; i++) {
            if (subseq[i] <= subseq[i - 1]) {
                return false;
            }
        }
        return true;
    }

    function generateSubsequences(index, currentSubseq) {
        if (index === nums.length) {
            if (isIncreasing(currentSubseq)) {
                longestLength = Math.max(longestLength, currentSubseq.length);
            }
            return;
        }
        // Include the current element
        generateSubsequences(index + 1, currentSubseq.concat(nums[index]));
        // Exclude the current element
        generateSubsequences(index + 1, currentSubseq);
    }

    let longestLength = 0;
    generateSubsequences(0, []);
    return longestLength;
}

