class Solution {
    public int longestIncreasingSubsequence(int[] data) {
        return findLIS(data, -1, 0);
    }
    private int findLIS(int[] data, int prevIndex, int currentIndex) {
        if (currentIndex == data.length) {
            return 0;
        }
        int taken = 0;
        if (prevIndex == -1 || data[currentIndex] > data[prevIndex]) {
            taken = 1 + findLIS(data, currentIndex, currentIndex + 1);
        }
        int notTaken = findLIS(data, prevIndex, currentIndex + 1);
        return Math.max(taken, notTaken);
    }
}

