package main

import "fmt"

func longestIncreasingSubsequence(data []int) int {
    var longest int
    var helper func(start int, current []int)
    helper = func(start int, current []int) {
        if len(current) > 1 {
            isIncreasing := true
            for i := 1; i < len(current); i++ {
                if current[i] <= current[i-1] {
                    isIncreasing = false
                    break
                }
            }
            if isIncreasing {
                if len(current) > longest {
                    longest = len(current)
                }
            }
        }
        for i := start; i < len(data); i++ {
            helper(i+1, append(current, data[i]))
        }
    }
    helper(0, []int{})
    return longest
}

func main() {
    data := []int{10, 22, 9, 33, 21, 50, 41, 60, 80}
    fmt.Println(longestIncreasingSubsequence(data)) // Output: 6
}

