class Solution {
    public int longestIncreasingSubsequence(int[] data) {
        if (data.length == 0) return 0;
        int[] tails = new int[data.length];
        int size = 0;
        for (int num : data) {
            int left = 0, right = size;
            while (left < right) {
                int mid = left + (right - left) / 2;
                if (tails[mid] < num) {
                    left = mid + 1;
                }
                else {
                    right = mid;
                }
            }
            tails[left] = num;
            if (left == size) size++;
        }
        return size;
    }
}

