using namespace std;
class Solution {
    public:
    int longestIncreasingSubsequence(const vector<int>& data) {
        if (data.empty()) return 0;
        vector<int> tails;
        for (int num : data) {
            auto it = lower_bound(tails.begin(), tails.end(), num);
            if (it == tails.end()) {
                tails.push_back(num);
            }
            else {
                *it = num;
            }
        }
        return tails.size();
    }
}
