package main

import (
    "fmt"
    "sort"
)

func longestIncreasingSubsequence(data []int) int {
    if len(data) == 0 {
        return 0
    }

    tails := []int{}
    for _, num := range data {
        index := sort.Search(len(tails), func(i int) bool {
            return tails[i] >= num
        })
        if index == len(tails) {
            tails = append(tails, num)
        } else {
            tails[index] = num
        }
    }
    return len(tails)
}

func main() {
    data := []int{10, 9, 2, 5, 3, 7, 101, 18}
    fmt.Println(longestIncreasingSubsequence(data)) // Output: 4
}

